import java.io.*;
import java.util.*;

public class Main {
    static long solveCase(int n, long[] marks) {
        // your code here — return the most frequent mark (smallest wins a tie)
        return marks[0];
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) sb.append(line).append(' ');
        StringTokenizer st = new StringTokenizer(sb.toString());
        int t = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            int n = Integer.parseInt(st.nextToken());
            long[] marks = new long[n];
            for (int i = 0; i < n; i++) marks[i] = Long.parseLong(st.nextToken());
            out.append(solveCase(n, marks)).append('\n');
        }
        System.out.print(out);
    }
}

